const crypto = require('crypto');

const source = items[0].json ?? {};
const headersInput = source.headers ?? {};
const headers = {};
for (const [key, value] of Object.entries(headersInput)) {
  headers[String(key).toLowerCase()] = Array.isArray(value) ? String(value[0] ?? '') : String(value ?? '');
}

const rawBodyText =
  typeof source.rawBody === 'string' ? source.rawBody :
  typeof source.body === 'string' ? source.body :
  source.body !== undefined ? JSON.stringify(source.body) :
  JSON.stringify(source);

let payload = source.body;
if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
  try {
    payload = JSON.parse(rawBodyText);
  } catch (error) {
    throw new Error(`Invalid JSON payload: ${error.message}`);
  }
}

const expectedToken = '__CHANGE_ME_WEBHOOK_TOKEN__';
if (expectedToken) {
  const providedToken = headers['x-webhook-token'] ?? '';
  if (providedToken !== expectedToken) {
    throw new Error('Invalid x-webhook-token header.');
  }
}

const secret = '__CHANGE_ME_HMAC_SECRET__';
const receivedSignature = headers['x-dte-signature'] ?? '';
const expectedSignature = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBodyText, 'utf8').digest('hex');
if (!receivedSignature || receivedSignature !== expectedSignature) {
  throw new Error('Invalid x-dte-signature header.');
}

return [{
  json: {
    ok: true,
    eventType: payload.event?.type ?? null,
    companyName: payload.company?.name ?? null,
    contratoId: payload.company?.contratoId ?? null,
    assunto: payload.message?.assunto ?? null,
    messageId: payload.message?.messageId ?? null,
    unreadLink: payload.links?.companyUnreadMessages ?? null,
    payload
  }
}];
